 58â†’// Run processes requests until shutdown or EOF. Returns nil on clean shutdown.
 59â†’func (h *Handler) Run() error {
 60â†’	h.log.Debug("Starting Go frontend", "protocol", ProtocolVersion)
 61â†’
 62â†’	for h.reader.Scan() {
 63â†’		line := h.reader.Text()
 64â†’		if line == "" {
 65â†’			continue
 66â†’		}
 67â†’
 68â†’		h.log.Log(context.Background(), LevelTrace, "Received", "raw", line)
 69â†’
 70â†’		var req Request
 71â†’		if err := json.Unmarshal([]byte(line), &req); err != nil {
 72â†’			h.log.Log(context.Background(), LevelTrace, "Failed to parse request", "err", err)
 73â†’			continue
 74â†’		}
 75â†’
 76â†’		resp, shutdown := h.dispatch(req)
 77â†’		if err := h.send(resp); err != nil {
 78â†’			return fmt.Errorf("writing response: %w", err)
 79â†’		}
 80â†’
 81â†’		if shutdown {
 82â†’			h.log.Debug("Shutting down")
 83â†’			return nil
 84â†’		}
 85â†’	}
 86â†’
 87â†’	if err := h.reader.Err(); err != nil {
 88â†’		return fmt.Errorf("reading stdin: %w", err)
 89â†’	}
 90â†’
 91â†’	h.log.Debug("Stdin closed, exiting")
 92â†’	return nil
 93â†’}
