 95â†’func (h *Handler) dispatch(req Request) (Response, bool) {
 96â†’	base := Response{
 97â†’		ProtocolVersion: ProtocolVersion,
 98â†’		ID:              req.ID,
 99â†’	}
100â†’
101â†’	if req.ProtocolVersion != ProtocolVersion {
102â†’		base.Status = "error"
103â†’		base.Code = ErrVersionMismatch
104â†’		base.Message = fmt.Sprintf(
105â†’			"unsupported protocol version %q, expected %q",
106â†’			req.ProtocolVersion, ProtocolVersion,
107â†’		)
108â†’		return base, false
109â†’	}
110â†’
111â†’	switch req.Command {
112â†’	case "handshake":
113â†’		return h.handleHandshake(base, req), false
114â†’	case "analyze":
115â†’		return h.handleAnalyze(base, req), false
116â†’	case "instrument":
117â†’		return h.handleInstrument(base, req), false
118â†’	case "execute":
119â†’		return h.handleExecute(base, req), false
120â†’	case "setup":
121â†’		return h.handleSetup(base, req), false
122â†’	case "teardown":
123â†’		return h.handleTeardown(base, req), false
124â†’	case "generate":
125â†’		return h.handleGenerate(base, req), false
126â†’	case "shutdown":
127â†’		return h.handleShutdown(base), true
128â†’	default:
129â†’		base.Status = "error"
130â†’		base.Code = ErrInvalidRequest
131â†’		base.Message = fmt.Sprintf("unknown command: %s", req.Command)
132â†’		return base, false
133â†’	}
134â†’}
